custom_css:
/* 口袋妖怪红宝石复古主题 | 优化版（强化GBA像素风+游戏元素） */
:root {
--theme-color-1: #C22832;
--theme-color-2: #0A7AAA;
--theme-yellow: #FFD100;
--ui-color-main: #F8F0E0;
--ui-color-sec: #E0C890;
--top-bar-color: #D9B38C;
--top-bar-underline-color: #8B4513;
--top-bar-icon-color: #5C3A21;
--chat-background-color: #F8F4E8;
--chat-bg-pattern: linear-gradient(rgba(139, 69, 19, 0.06) 1px, transparent 1px),
linear-gradient(90deg, rgba(139, 69, 19, 0.06) 1px, transparent 1px);
--text-color-main: #3A2E2F;
--text-color-sec: #8B4513;
--user-color: #FFF8E0;
--char-color: #F9F3E5;
--code-color: #D4B886;
--gradient-main: linear-gradient(135deg, var(--theme-color-1) 30%, var(--theme-yellow) 50%, var(--theme-color-2) 70%);
--pixel-border: 3px solid #8B4513;
--pixel-shadow: 3px 3px 0px #6D3A10;
--pixel-inner-shadow: inset 1px 1px 0px rgba(255, 255, 255, 0.3),
inset -1px -1px 0px rgba(109, 58, 16, 0.3);
--drawer-bg: var(--ui-color-sec);
--drawer-content-bg: var(--ui-color-main);
--mes-width: 100%;
--mes-block-width: 98%;
--box-border-radius: 0px;
--border-radius-small: 0px;
--border-radius-medium: 0px;
--top-distance: 0px;
--bottom-distance: 0px;
--chat-send-spacing: 0px;
--leftRight-chat-spacing: 0px;
--scroll-width: 8px;
--spacing-long: 6px;
--spacing-short: 3px;
--icon-size: var(--mainFontSize);
--topBarIconSize: calc(var(--icon-size) * 1.8);
--mes-safe-area: 80px;
--quote-bg: var(--theme-color-2);
--quote-border: 2px solid #085F8A;
--animate-duration: 0.3s;
--animate-easing: cubic-bezier(0.25, 0.1, 0.25, 1);
--token-init-width: 20px;
--token-expand-width: 80px;
--floor-init-width: 40px;
--floor-expand-width: 60px;
--italic-color: #3A0700;
}

*:not(i, .fa-solid, .fa-fw, icon) {
font-family: 'Press Start 2P', 'Pixelify Sans', monospace !important;
letter-spacing: 0.03em;
-webkit-font-smoothing: none;
font-smooth: never;
text-rendering: optimizeSpeed;
}

.standoutHeader strong,
#right-nav-panel h2,
.drawer-content > h3,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *) {
font-size: calc(var(--mainFontSize) * 1.1);
font-weight: 400;
color: var(--text-color-main);
letter-spacing: 0.12em;
line-height: 2.2;
text-shadow: 1px 1px 0px #E0C890, 2px 2px 0px rgba(139, 69, 19, 0.2);
}

.standoutHeader strong::before,
#right-nav-panel h2::before,
.drawer-content > h3::before,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
.drawer-content .flex-container .flex-container h3:first-of-type::before,
.popup h3:not(dialog *)::before {
content: "";
display: inline-block;
width: 16px;
height: 16px;
background: radial-gradient(circle at 50% 50%, white 2px, #333 3px, #333 4px, transparent 4px),
linear-gradient(to bottom, #D02020 48%, #333 48%, #333 52%, white 52%);
border: 1px solid #333;
border-radius: 50%;
margin-right: 8px;
vertical-align: middle;
box-shadow: 1px 1px 0 rgba(0,0,0,0.2);
text-shadow: none;
letter-spacing: normal;
}

.standoutHeader:not(h4),
#rm_PinAndTabs,
#top-settings-holder .drawer:not(:first-child):not(:last-child) .drawer-content .alignItemsBaseline.wide100p,
#rm_api_block .flex-container.alignItemsBaseline,
#title_api,
#AdvancedFormatting .flex-container.alignItemsBaseline:not(h3),
#WorldInfo .alignitemscenter:not(#world_popup *),
#user-settings-block div[name="userSettingsRowOne"],
#rm_extensions_block .alignitemscenter.flex-container.wide100p:not(.justifyCenter) {
border-bottom: 3px solid var(--top-bar-underline-color);
padding-bottom: calc(var(--mainFontSize) * 0.2);
margin-bottom: calc(var(--mainFontSize) * 0.5);
box-shadow: 0 2px 0px rgba(109, 58, 16, 0.2);
}

.drawer {
background: var(--drawer-bg) !important;
border-right: 3px solid #8B4513;
color: var(--top-bar-icon-color);
box-shadow: var(--pixel-inner-shadow), 2px 0 0px rgba(109, 58, 16, 0.2);
}

.drawer:has(.openDrawer) {
background: var(--drawer-content-bg) !important;
box-shadow: inset 0 0 0 1px rgba(139, 69, 19, 0.2), var(--pixel-inner-shadow);
}

.drawer-content {
background: var(--drawer-content-bg) !important;
padding: var(--spacing-long);
box-shadow: var(--pixel-inner-shadow);
}

#top-settings-holder .drawer {
background: var(--drawer-bg) !important;
border-bottom: 3px solid #8B4513;
border-right: none;
}

#top-settings-holder .drawer-content {
background: var(--drawer-content-bg) !important;
border-top: 1px solid rgba(139, 69, 19, 0.1);
}

.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#top-settings-holder h4:not(#ai-config-button *):not(#rightNavHolder *) {
border-left: 5px solid var(--theme-color-1);
padding-left: var(--spacing-long);
background: var(--ui-color-sec);
box-shadow: var(--pixel-inner-shadow);
margin: 0 -var(--spacing-long);
padding-right: var(--spacing-long);
}

.inline-drawer-content {
background: var(--drawer-content-bg) !important;
padding: var(--spacing-long) 0;
}

.inline-drawer-icon {
font-size: calc(var(--icon-size) * 0.9);
color: var(--theme-color-2);
text-shadow: var(--pixel-shadow);
transition: color 0.1s ease;
}

.inline-drawer-icon:hover {
color: var(--theme-yellow);
}

.drawer-list-item {
background: transparent;
transition: background 0.1s ease;
}

.drawer-list-item:hover,
.drawer-list-item.active {
background: color-mix(in srgb, var(--theme-yellow) 20%, transparent);
border-left: 3px solid var(--theme-yellow);
}

::-webkit-scrollbar {
width: var(--scroll-width);
height: var(--scroll-width);
background: var(--ui-color-sec);
border-left: 1px solid #8B4513;
}

::-webkit-scrollbar-thumb {
background: var(--theme-color-1);
border: 2px solid #8B4513;
box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.2);
}

::-webkit-scrollbar-thumb:hover {
background: var(--theme-yellow);
}

input[type="text"],
input[type="number"],
input:not([type]),
textarea:not([type="search"]),
.text_pole:not(.objective-task) {
background: var(--ui-color-main);
border: var(--pixel-border);
box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
padding: 4px 6px;
}

input[type="text"]:focus,
input[type="number"]:focus,
input:not([type]):focus,
textarea:not([type="search"]):focus {
border-color: var(--theme-yellow);
box-shadow: 0 0 0 3px rgba(255, 209, 0, 0.3), var(--pixel-shadow);
outline: none;
}

select {
background: var(--ui-color-main);
border: var(--pixel-border);
box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
color: var(--text-color-main);
padding: 2px 4px;
appearance: none;
background-image: url("data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%238B4513' stroke-width='3' stroke-linecap='square' stroke-linejoin='arcs'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e");
background-repeat: no-repeat;
background-position: right 4px center;
background-size: 16px;
}

.menu_button:not(.mes_edit_buttons *) {
background: var(--ui-color-sec);
border: var(--pixel-border);
color: var(--text-color-main);
box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
transition: transform 0.08s ease, background 0.08s ease, box-shadow 0.08s ease;
padding: 6px 10px;
}

.menu_button:hover {
background: color-mix(in srgb, var(--ui-color-sec) 70%, var(--theme-yellow) 30%);
transform: translate(1px, 1px);
box-shadow: 1px 1px 0px #6D3A10, var(--pixel-inner-shadow);
}

.menu_button:active {
transform: translate(2px, 2px);
box-shadow: none;
background: color-mix(in srgb, var(--ui-color-sec) 80%, var(--theme-color-1) 20%);
}

.redWarningBG,
.red_button,
#delete_button,
#dialogue_del_mes_ok,
#dialogue_popup_ok {
background: var(--theme-color-1) !important;
color: #FFF8DC !important;
border: 3px solid #8B0000 !important;
box-shadow: var(--pixel-shadow), inset 1px 1px 0px rgba(255, 255, 255, 0.2);
}

.redWarningBG:hover,
.red_button:hover {
background: #A02020 !important;
}

#top-bar,
body.no-blur #top-bar {
background: var(--top-bar-color) !important;
border-bottom: 3px solid #8B4513;
box-shadow: 0 3px 0px rgba(139, 69, 19, 0.4);
}

.drawer-icon {
font-size: calc(var(--icon-size) * 1.2);
text-shadow: var(--pixel-shadow);
opacity: 0.8;
transition: color 0.1s ease, opacity 0.1s ease;
}

.drawer-icon:hover,
.drawer-icon.openIcon {
opacity: 1;
color: var(--theme-yellow);
}

#sheld {
top: calc(var(--topBarBlockSize) + var(--top-distance));
height: calc(100dvh - var(--topBarBlockSize) - var(--top-distance) - 1px);
}

#chat {
overflow-y: scroll;
align-items: center;
max-height: calc(100dvh - var(--topBarBlockSize) - 20px) !important;
padding: calc(var(--scroll-width) + 4px) 0 var(--scroll-width) var(--scroll-width);
border-radius: 0;
background-color: var(--chat-background-color);
background-image: var(--chat-bg-pattern);
background-size: 16px 16px;
}

@supports (-webkit-touch-callout: none) {
#chat {
padding-right: var(--scroll-width);
}
}

.mes {
position: relative !important;
overflow: visible !important;
width: var(--mes-width);
max-width: 680px;
margin: 12px auto !important;
border: var(--pixel-border) !important;
background-color: var(--ui-color-main) !important;
box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
padding: 0 !important;
}

#chat .mes_block {
position: relative !important;
width: var(--mes-block-width);
padding: var(--mes-safe-area) 12px 12px 12px !important;
margin: 0 !important;
}

#chat .mesAvatarWrapper {
position: absolute !important;
top: 12px !important;
left: 12px !important;
width: 60px !important;
height: 60px !important;
z-index: 10 !important;
margin: 0 !important;
display: block !important;
transition: transform var(--animate-duration) var(--animate-easing);
}

#chat .mes[is_user="true"] .mesAvatarWrapper {
left: auto !important;
right: 12px !important;
}

#chat .mes:hover .mesAvatarWrapper {
transform: scale(1.05);
}

#chat .mes .avatar {
position: absolute !important;
width: 50px !important;
height: 50px !important;
top: 50% !important;
left: 50% !important;
transform: translate(-50%, -50%) !important;
margin: 0 !important;
border: 2px solid #8B4513 !important;
border-radius: 0 !important;
box-shadow: var(--pixel-shadow) !important;
transition: box-shadow var(--animate-duration) var(--animate-easing);
}

#chat .mes:hover .avatar {
box-shadow: var(--pixel-shadow), 0 0 0 2px var(--theme-yellow);
}

/* 恢复为第一个代码的头像基础阴影样式 */
.avatar img,
body.big-avatars .avatar img {
box-shadow: var(--pixel-shadow), 0 0 6px rgba(139, 69, 19, 0.3) !important;
border: none !important;
border-radius: 0 !important;
object-fit: cover !important;
}

#chat .ch_name {
position: absolute !important;
top: 20px !important;
left: 80px !important;
color: var(--theme-color-1);
font-weight: 600;
text-shadow: 1px 1px 0px #E0C890, 2px 2px 0px rgba(139, 69, 19, 0.2);
font-size: calc(var(--mainFontSize) * 0.9);
letter-spacing: 0.08em;
padding: 0 !important;
margin: 0 !important;
max-width: 200px !important;
overflow: hidden !important;
white-space: nowrap !important;
transition: max-width var(--animate-duration) var(--animate-easing);
}

#chat .mes[is_user="true"] .ch_name {
left: auto !important;
right: 80px !important;
color: var(--theme-color-2);
text-align: right !important;
}

#chat .mes:hover .ch_name {
max-width: 300px !important;
}

#chat .ch_name::after {
content: "";
position: absolute;
bottom: -2px;
left: 0;
width: 100%;
height: 2px;
background-color: var(--theme-color-1);
box-shadow: 0 1px 0px rgba(139, 69, 19, 0.3);
transition: background-color var(--animate-duration) var(--animate-easing);
}

#chat .mes[is_user="true"] .ch_name::after {
background-color: var(--theme-color-2);
left: auto !important;
right: 0 !important;
}

.mes_timer {
position: absolute !important;
top: 45px !important;
left: 80px !important;
color: var(--text-color-sec);
font-size: calc(var(--mainFontSize) * 0.7);
letter-spacing: 0.02em;
display: block !important;
margin: 0 !important;
}

#chat .mes[is_user="true"] .mes_timer {
left: auto !important;
right: 80px !important;
text-align: right !important;
}

.mesIDDisplay {
position: absolute !important;
top: -12px !important;
left: 10px !important;
color: var(--text-color-sec);
font-size: calc(var(--mainFontSize) * 0.7);
letter-spacing: 0.02em;
display: inline-block !important;
background: var(--ui-color-sec) !important;
border: 1px solid #8B4513 !important;
padding: 1px 4px !important;
box-shadow: var(--pixel-shadow) !important;
z-index: 6 !important;
max-width: var(--floor-init-width) !important;
overflow: hidden !important;
white-space: nowrap !important;
transition: max-width var(--animate-duration) var(--animate-easing);
}

.tokenCounterDisplay {
position: absolute !important;
top: -12px !important;
left: 55px !important;
color: var(--text-color-sec);
font-size: calc(var(--mainFontSize) * 0.7);
letter-spacing: 0.02em;
display: inline-block !important;
background: var(--ui-color-sec) !important;
border: 1px solid #8B4513 !important;
padding: 1px 4px !important;
box-shadow: var(--pixel-shadow) !important;
z-index: 5 !important;
max-width: var(--token-init-width) !important;
overflow: hidden !important;
white-space: nowrap !important;
transition: max-width var(--animate-duration) var(--animate-easing);
}

.tokenCounterDisplay::before {
content: "" !important;
margin: 0 !important;
}

.mes:hover .mesIDDisplay {
max-width: var(--floor-expand-width) !important;
}

.mes:hover .tokenCounterDisplay {
max-width: var(--token-expand-width) !important;
}

.mes:hover .tokenCounterDisplay::before {
content: "|" !important;
margin: 0 3px !important;
color: var(--text-color-sec);
}

.mes_text {
position: relative !important;
padding: 0 !important;
margin: 0 !important;
line-height: 1.4;
font-size: calc(var(--mainFontSize) * 0.95);
letter-spacing: 0.02em;
text-shadow: 0.5px 0.5px 0px rgba(255, 255, 255, 0.5);
}

.mes_text em {
color: var(--italic-color) !important;
font-style: italic !important;
text-shadow: 0.5px 0.5px 0px rgba(255, 255, 255, 0.3) !important;
}

.mes_text q {
display: inline !important;
background-color: var(--quote-bg) !important;
color: #FFF8E0 !important;
border: var(--quote-border) !important;
border-radius: 0 !important;
padding: 2px 6px !important;
margin: 0 2px !important;
-webkit-box-decoration-break: clone !important;
box-decoration-break: clone !important;
line-height: 1.8 !important;
text-shadow: 1px 1px 0px rgba(0, 0, 0, 0.2) !important;
letter-spacing: 0.03em !important;
}

div[is_user="true"] .mes_text q {
background-color: var(--theme-color-1) !important;
border-color: #A02020 !important;
}

.mes_reasoning_header {
position: relative !important;
background: color-mix(in srgb, var(--theme-color-1) 20%, transparent);
border: 2px solid #8B4513;
box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
font-size: calc(var(--mainFontSize) * 0.85);
margin: 0 0 8px 0 !important;
padding: 4px 8px !important;
}

.mes_reasoning_header span::before {
content: "🔍";
margin-right: 5px;
color: var(--theme-color-1);
text-shadow: var(--pixel-shadow);
}

#chat .mes_block .mes_buttons_wrapper {
position: absolute !important;
top: 10px !important;
right: 10px !important;
left: auto !important;
transform: none !important;
z-index: 99 !important;
display: flex !important;
gap: 4px !important;
}

#chat .mes_block .mes_buttons_wrapper > .mes_button {
background-color: var(--ui-color-sec) !important;
border: 2px solid #8B4513 !important;
border-radius: 0 !important;
padding: 0 !important;
min-width: 24px !important;
min-height: 24px !important;
box-shadow: 2px 2px 0px #6D3A10 !important;
filter: none !important;
aspect-ratio: 1 !important;
}

#chat .mes_block .mes_buttons_wrapper > .mes_button > .fa,
#chat .mes_block .mes_buttons_wrapper > .mes_button::before {
font-size: 12px !important;
color: var(--text-color-main) !important;
text-shadow: none !important;
}

.mes::before {
content: "";
position: absolute;
top: 0;
left: 0;
width: 8px;
height: 8px;
border-right: 2px solid #6D3A10;
border-bottom: 2px solid #6D3A10;
z-index: 1 !important;
}

.mes::after {
content: "";
position: absolute;
bottom: 0;
right: 0;
width: 8px;
height: 8px;
border-left: 2px solid #6D3A10;
border-top: 2px solid #6D3A10;
z-index: 1 !important;
}

div[is_user="true"] {
background-color: var(--user-color) !important;
border-color: var(--theme-color-2) !important;
}

/* 恢复为第一个代码的用户头像阴影样式 */
div[is_user="true"] .avatar img {
box-shadow: 0 0 0 3px var(--theme-color-2), var(--pixel-shadow), 0 0 8px rgba(10, 122, 170, 0.4) !important;
}

div[is_user="false"] {
background-color: var(--char-color) !important;
border-color: var(--theme-color-1) !important;
}

/* 恢复为第一个代码的AI头像阴影样式 */
div[is_user="false"] .avatar img {
box-shadow: 0 0 0 3px var(--theme-color-1), var(--pixel-shadow), 0 0 8px rgba(194, 40, 50, 0.4) !important;
}

.swipe_left {
left: calc(var(--scroll-width) + var(--spacing-short));
background: var(--ui-color-sec) !important;
border: 2px solid #8B4513 !important;
box-shadow: var(--pixel-shadow) !important;
}

.swipeRightBlock {
flex-direction: row-reverse;
bottom: 8px !important;
right: 8px !important;
position: absolute !important;
}

.swipes-counter {
margin-bottom: 0 !important;
margin-left: 4px !important;
font-size: calc(var(--mainFontSize) * 0.8);
background: var(--ui-color-sec);
border: 2px solid #8B4513;
padding: 1px 4px;
box-shadow: var(--pixel-shadow);
}

#send_form,
body.no-blur #send_form {
background: var(--ui-color-main) !important;
border: 3px solid #8B4513;
box-shadow: var(--pixel-shadow), var(--pixel-inner-shadow);
padding: 0 5px;
}

#send_form textarea {
background: transparent !important;
border: 2px solid #8B4513 !important;
box-shadow: inset 2px 2px 0px rgba(139, 69, 19, 0.2),
inset -1px -1px 0px rgba(255, 255, 255, 0.3);
padding: 6px 8px;
}

#send_button {
background: var(--theme-color-1) !important;
color: #FFF8DC !important;
border: 3px solid #8B0000 !important;
}

#send_button:hover {
background: #A02020 !important;
transform: translate(1px, 1px);
}

#send_button:active {
transform: translate(2px, 2px);
}

code,
.hljs,
.custom-mermaid {
background: var(--code-color);
border: 3px solid #8B4513;
font-family: 'Press Start 2P', monospace !important;
font-size: calc(var(--mainFontSize) * 0.8);
box-shadow: var(--pixel-inner-shadow);
padding: 4px 6px;
white-space: pre-wrap !important;
word-wrap: break-word !important;
}

.mes_text pre {
max-height: 300px !important;
overflow-y: auto !important;
}

.popup,
dialog {
background: var(--ui-color-main) !important;
border: 3px solid #8B4513 !important;
box-shadow: var(--pixel-shadow), 0 0 0 4px rgba(139, 69, 19, 0.2) !important;
border-radius: 0 !important;
}

@media screen and (max-width: 1000px) {
#left-nav-panel,
#right-nav-panel {
height: calc(100dvh - 45px) !important;
border-right: 3px solid #8B4513 !important;
}

.mes {
max-width: 95% !important;
}

.mes_text {
font-size: calc(var(--mainFontSize) * 0.9);
}

.ch_name {
font-size: calc(var(--mainFontSize) * 0.85) !important;
}

#chat .mesAvatarWrapper {
width: 50px !important;
height: 50px !important;
}

#chat .mes .avatar {
width: 40px !important;
height: 40px !important;
}

.mesIDDisplay {
max-width: 30px !important;
}
.tokenCounterDisplay {
max-width: 15px !important;
left: 45px !important;
}
.mes:hover .mesIDDisplay {
max-width: 50px !important;
}
.mes:hover .tokenCounterDisplay {
max-width: 60px !important;
}
}

@supports (-webkit-touch-callout: none) {
@media screen and (min-width: 1000px) {
#left-nav-panel,
#right-nav-panel {
top: calc(var(--topBarBlockSize) + var(--top-distance));
max-height: calc(100dvh - var(--topBarBlockSize) - var(--bottomFormBlockSize));
border-right: 3px solid #8B4513 !important;
}
}
}

#ReverseProxyWarningMessage {
display: none !important;
}
